const input = $input.first().json;
const query = (input.query || input.message || input.text || input.originalMessage || '').trim();
const chatId = (input.chatId || input.chat_id || '-1003688744736').toString();

const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const hour = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');
const day = now.getDate();
const dayOfWeek = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'][now.getDay()];
const month = now.toLocaleString('es-CO', { month: 'long' }).toUpperCase();
const fullDate = now.toLocaleDateString('es-ES');

return { json: { query, chatId, time: { hour, day, dayOfWeek, month, fullDate } } };

// Extrae lista de hábitos de la hoja para el Agente Identificador
const rows = $input.all();
const parser = $('📦 Parser').first().json;

const habits = [];
for (const item of rows) {
  const row = item.json;
  if (row.row_number < 10 || row.row_number > 26) continue;
  const name = row['col_2'] || row['B'] || Object.values(row).find(v => typeof v === 'string' && v.length > 3 && v.length < 60) || '';
  if (name) {
    habits.push({ row_number: row.row_number, name: name.trim() });
  }
}

return { json: {
  query: parser.query,
  chatId: parser.chatId,
  time: parser.time,
  habitList: habits,
  habitNames: habits.map(h => `[Row ${h.row_number}] ${h.name}`).join('\n')
}};

// ═══════════════════════════════════════════════════════════════
// 🔗 BRIDGE — Parsea Agent JSON + prepara datos para Sheets
// Reemplaza 300 líneas de fuzzy matching con ~60 líneas
// ═══════════════════════════════════════════════════════════════

const agentRaw = $input.first().json;
const prep = $('📊 Prep Identificador').first().json;
const parser = $('📦 Parser').first().json;

// Parsear JSON del agente
let ai;
try {
  let text = agentRaw.text || agentRaw.output || agentRaw.message || agentRaw.response || '';
  if (typeof text === 'object' && text.found !== undefined) { ai = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  ai = { found: false, habitName: '', row_number: 0, isFailure: false, isSuccess: false, excuse: '', confidence: 'none', reason: 'Error parsing agent response: ' + e.message };
}

const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const todayNum = now.getDate().toString();
const fullDate = now.toLocaleDateString('es-ES');

if (ai.found && ai.row_number > 0) {
  return [{ json: {
    encontrado: true,
    row_number: ai.row_number,
    habitName: ai.habitName,
    chatId: parser.chatId,
    dayColumn: todayNum,
    markValue: ai.isFailure ? 'FALSE' : 'TRUE',
    isFailure: ai.isFailure || false,
    isSuccess: ai.isSuccess || true,
    excuse: ai.excuse || '',
    confidence: ai.confidence || 'high',
    E: fullDate,
    F: ai.habitName,
    G: ai.excuse || '',
    query: parser.query,
    time: parser.time
  }}];
} else {
  return [{ json: {
    encontrado: false,
    chatId: parser.chatId,
    reason: ai.reason || 'Hábito no identificado',
    query: parser.query,
    time: parser.time
  }}];
}

// ═══════════════════════════════════════════════════════════════
// 📊 CALCULAR PROGRESO — Simplificado (math real, no reemplazable por LLM)
// ═══════════════════════════════════════════════════════════════

try {
  const bridge = $('🔗 Bridge').first().json;
  const updatedData = $('📋 Leer Actualizado').all();
  const parser = $('📦 Parser').first().json;

  const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
  const day = now.getDate();
  const month = now.toLocaleString('es-CO', { month: 'long' }).toUpperCase();
  const hour = parser.time.hour;

  function getDayValue(row, targetDay) {
    const dayStr = String(targetDay);
    if (row.hasOwnProperty(dayStr)) return row[dayStr];
    for (const key of Object.keys(row)) {
      if (key.trim() === dayStr || parseInt(key) === targetDay) return row[key];
    }
    return undefined;
  }

  function isCompleted(val) {
    if (val === undefined || val === null || val === '') return false;
    if (val === true || val === 1) return true;
    const str = String(val).toUpperCase().trim();
    return ['TRUE','SI','SÍ','VERDADERO','1','HECHO','DONE','X','✓','✔','✅'].includes(str);
  }

  function getHabitName(row) {
    return row['col_2'] || row['B'] || row['Hábito'] || row['Habito'] ||
      Object.values(row).find(v => typeof v === 'string' && v.length > 3 && v.length < 50) || 'Hábito';
  }

  let total = 0, completed = 0, racha = 0;
  let pendingList = [], completedList = [];

  for (const item of updatedData) {
    const row = item.json;
    if (row.row_number < 10 || row.row_number > 26) continue;
    total++;
    const val = getDayValue(row, day);
    const name = getHabitName(row);
    if (isCompleted(val)) { completed++; completedList.push(name); }
    else { pendingList.push(name); }

    // Racha solo para el hábito actual
    if (row.row_number === bridge.row_number && !bridge.isFailure) {
      racha = 0;
      for (let d = day; d >= 1; d--) {
        if (isCompleted(getDayValue(row, d))) racha++; else break;
      }
    }
  }

  const porcentaje = total > 0 ? Math.round((completed / total) * 100) : 0;
  let motivationalState = 'neutral';
  if (porcentaje >= 90) motivationalState = 'excellent';
  else if (porcentaje >= 70) motivationalState = 'good';
  else if (porcentaje >= 50) motivationalState = 'moderate';
  else motivationalState = 'needsWork';

  return [{ json: {
    habitName: bridge.habitName, isFailure: bridge.isFailure,
    excuse: bridge.excuse || 'Sin detalle',
    porcentaje, completados: completed, total, racha,
    pendingList: pendingList.join(', '), pendingCount: pendingList.length,
    completedList: completedList.join(', '),
    day, month, hour, motivationalState,
    userMessage: parser.query, chatId: parser.chatId, time: parser.time
  }}];
} catch(e) {
  return [{ json: { error: true, textResponse: '❌ Error: ' + e.message, chatId: '' } }];
}

