// 📤 OUTPUT — Parsea JSON del Auditor
// FIX: try/catch seguro cuando Calcular Progreso no corrió (ruta de error)

const raw = $input.first().json;

let progress = {};
try {
  progress = $('📊 Calcular Progreso').first().json;
} catch(e) {
  progress = { habitName: 'No identificado', isFailure: false, racha: 0, chatId: '' };
}

let final;
try {
  let text = raw.text || raw.output || raw.message || raw.response || '';
  if (typeof text === 'object' && text.telegramPayload) { final = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) final = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  final = {
    telegramPayload: {
      chat_id:    progress.chatId || '',
      text:       `${progress.isFailure ? '❌' : '✅'} *${progress.habitName || 'Hábito'}*\n\n${progress.isFailure ? 'Fallado' : 'Completado'}. Racha: ${progress.racha || 0}`,
      parse_mode: 'Markdown'
    },
    toolResponse: `${progress.isFailure ? '❌' : '✅'} ${progress.habitName || 'Hábito'} registrado`
  };
}

return [{ json: final }];

// Error: hábito no encontrado
const bridge = $input.first().json;
return [{ json: {
  habitName: 'No identificado', isFailure: false,
  excuse: '', porcentaje: 0, completados: 0, total: 0, racha: 0,
  pendingList: '', pendingCount: 0, completedList: '',
  day: 0, month: '', hour: '',
  motivationalState: 'error',
  userMessage: bridge.query || '', chatId: bridge.chatId,
  time: bridge.time || {},
  errorMode: true, reason: bridge.reason || 'No encontrado'
}}];
